        System.Threading.Tasks.Task<ApiResponse<AgentConversationHistoryResponse>> GetConversationListWithHttpInfoAsync(int? limit = default(int?), int? offset = default(int?), bool? skipEmpty = default(bool?), System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));
        /// <summary>
        /// 
        /// </summary>
        /// <remarks>
