        /// <param name="cancellationToken">Cancellation Token to cancel the request.</param>
        /// <returns>Task of ApiResponse (LoadAnswerResponse)</returns>
        System.Threading.Tasks.Task<ApiResponse<LoadAnswerResponse>> LoadAnswerWithHttpInfoAsync(string conversationIdentifier, string answerIdentifier, System.Threading.CancellationToken cancellationToken = default(global::System.Threading.CancellationToken));
