        /// Initializes a new instance of the <see cref="AIApi"/> class.
        /// **IMPORTANT** This will also create an instance of HttpClient, which is less than ideal.
        /// It's better to reuse the <see href="https://docs.microsoft.com/en-us/dotnet/architecture/microservices/implement-resilient-applications/use-httpclientfactory-to-implement-resilient-http-requests#issues-with-the-original-httpclient-class-available-in-net">HttpClient and HttpClientHandler</see>.
        /// </summary>
        /// <param name="basePath">The target service's base path in URL format.</param>
        /// <exception cref="ArgumentException"></exception>
        /// <returns></returns>
        public AIApi(string basePath)
        {
            this.Configuration = ThoughtSpot.Client.Client.Configuration.MergeConfigurations(
                ThoughtSpot.Client.Client.GlobalConfiguration.Instance,
                new ThoughtSpot.Client.Client.Configuration { BasePath = basePath }
            );
            var handler = new System.Net.Http.HttpClientHandler();
            var httpClient = new System.Net.Http.HttpClient(handler) { Timeout = System.TimeSpan.FromSeconds(300) };
            this.ApiClient = new ThoughtSpot.Client.Client.ApiClient(httpClient, this.Configuration.BasePath, handler);
            this.Client =  this.ApiClient;
            this.AsynchronousClient = this.ApiClient;
            this.ExceptionFactory = ThoughtSpot.Client.Client.Configuration.DefaultExceptionFactory;
        }

