        /// <summary>
        /// Creates a <see cref="AIApi"/> with automatic bearer-token injection and refresh.
        /// The token is fetched on first call and refreshed automatically before it expires.
        /// </summary>
        /// <param name="config">Connection settings including host, credentials, and SSL options.</param>
        /// <param name="cancellationToken">Optional cancellation token.</param>
        public static async System.Threading.Tasks.Task<AIApi> CreateAsync(
            ThoughtSpot.Client.ApiClientConfiguration config,
            System.Threading.CancellationToken cancellationToken = default)
        {
            var hasPassword  = config.Username is not null && config.Password  is not null;
            var hasSecretKey = config.Username is not null && config.SecretKey is not null;

            if (!hasPassword && !hasSecretKey && config.TokenProvider is null && config.BearerToken is null)
                throw new ArgumentException(
                    "Provide Username+Password, Username+SecretKey, a TokenProvider, or a BearerToken.");

            System.Func<System.Threading.Tasks.Task<string>>? tokenProvider = null;

            var handler = new System.Net.Http.HttpClientHandler();
            if (config.IgnoreSslErrors)
                handler.ServerCertificateCustomValidationCallback =
                    System.Net.Http.HttpClientHandler.DangerousAcceptAnyServerCertificateValidator;

            var injectingHandler = new ThoughtSpot.Client.Client.TokenInjectingHandler(
                async () => tokenProvider is null ? string.Empty : await tokenProvider(),
                handler);

            var httpClient = new System.Net.Http.HttpClient(injectingHandler)
            {
                Timeout               = config.Timeout == System.TimeSpan.Zero ? System.TimeSpan.FromSeconds(300) : config.Timeout,
                DefaultRequestVersion = System.Net.HttpVersion.Version11,
                DefaultVersionPolicy  = System.Net.Http.HttpVersionPolicy.RequestVersionOrLower,
            };

            foreach (var (key, value) in config.DefaultHeaders)
                httpClient.DefaultRequestHeaders.TryAddWithoutValidation(key, value);

            var cfg = new ThoughtSpot.Client.Client.Configuration { BasePath = config.Host.TrimEnd('/') };

            if (config.TokenProvider is not null)
            {
                tokenProvider = config.TokenProvider;
            }
            else if (config.BearerToken is not null)
            {
#pragma warning disable CS0618
                tokenProvider = () => System.Threading.Tasks.Task.FromResult(config.BearerToken);
#pragma warning restore CS0618
            }
            else
            {
                var tokenRequest = new ThoughtSpot.Client.Model.GetFullAccessTokenRequest(
                    username:          config.Username!,
                    password:          config.Password,
                    secretKey:         config.SecretKey,
                    validityTimeInSec: config.TokenValiditySeconds);

                var authApi = new ThoughtSpot.Client.Api.AuthenticationApi(httpClient, cfg, handler);

                var first = await authApi.GetFullAccessTokenAsync(
                    tokenRequest, cancellationToken: cancellationToken);

                var cachedToken = first.VarToken
                    ?? throw new InvalidOperationException("Auth succeeded but token was null.");

                var expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);

                tokenProvider = async () =>
                {
                    if (DateTimeOffset.UtcNow < expiresAt)
                        return cachedToken;

                    expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds);

                    var refreshed = await authApi.GetFullAccessTokenAsync(tokenRequest);
                    cachedToken = refreshed.VarToken
                        ?? throw new InvalidOperationException("Token refresh returned null.");
                    expiresAt = DateTimeOffset.UtcNow.AddSeconds(config.TokenValiditySeconds - 30);
                    return cachedToken;
                };
            }

